import java.io.*; import java.net.*; import java.util.*; public class GameServer { private static final List<PrintWriter> clients = new ArrayList<>(); private static final List<ClientHandler> handlers = new ArrayList<>(); public static void main(String[] args) throws Exception { ServerSocket server = new ServerSocket(5000); System.out.println("Server running at IP: " + InetAddress.getLocalHost().getHostAddress()); System.out.println("Server started on port 5000..."); System.out.println("Waiting for 2 players..."); int playerId = 1; while (playerId <= 2) { Socket socket = server.accept(); System.out.println("Player " + playerId + " connected!"); PrintWriter out = new PrintWriter(socket.getOutputStream(), true); clients.add(out); out.println("ID:" + playerId); ClientHandler handler = new ClientHandler(socket, playerId, handlers); handlers.add(handler); new Thread(handler).start(); playerId++; } System.out.println("Maximum players connected. Server is full."); } public static void broadcast(String msg) { for (PrintWriter w : clients) { w.println(msg); } } static class ClientHandler implements Runnable { private Socket socket; private int playerId; private List<ClientHandler> handlers; private BufferedReader in; private PrintWriter out; public ClientHandler(Socket socket, int playerId, List<ClientHandler> handlers) { this.socket = socket; this.playerId = playerId; this.handlers = handlers; } @Override public void run() { try { in = new BufferedReader(new InputStreamReader(socket.getInputStream())); out = new PrintWriter(socket.getOutputStream(), true); String msg; while ((msg = in.readLine()) != null) { if (msg.startsWith("POS:")) { System.out.println("Player " + playerId + ": " + msg); GameServer.broadcast(msg); } } socket.close(); handlers.remove(this); System.out.println("Player " + playerId + " disconnected."); } catch (Exception e) { e.printStackTrace(); } } }}